**Proxy Controller**

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet("{endpoint}")]
    public async Task<IActionResult> GetAsync([FromRoute] string endpoint)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var response = await httpClient.GetAsync(endpoint);
        response.EnsureSuccessStatusCode();
        return Ok(await response.Content.ReadAsStringAsync());
    }

    [HttpPost("{endpoint}")]
    public async Task<IActionResult> PostAsync([FromRoute] string endpoint, [FromBody] string data)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var content = new StringContent(data, Encoding.UTF8, "text/plain");
        var response = await httpClient.PostAsync(endpoint, content);
        response.EnsureSuccessStatusCode();
        return Ok(await response.Content.ReadAsStringAsync());
    }
}
```

