Below is a simple Lit component written in TypeScript that counts the number of times it has been clicked and displays the count.

```typescript
// counter.ts
import { html, LitElement, property } from 'lit';

export class Counter extends LitElement {
  @property({ type: Number }) count = 0;

  private _handleClick() {
    this.count++;
    this.requestUpdate();
  }

  render() {
    return html`
      <button @click=${this._handleClick}>Click me!</button>
      <p>Clicked ${this.count} times.</p>
    `;
  }
}

